from itertools import groupby

class Solution:
    def longestRepeating(self, s, queryCharacters, queryIndices):
        arr = list(s)
        result = []
        for c, idx in zip(queryCharacters, queryIndices):
            arr[idx] = c
            result.append(max(len(list(g)) for _, g in groupby(arr)))
        return result

