class Solution:
    def longestRepeating(self, s, queryCharacters, queryIndices):
        arr = list(s)
        result = []
        for c, idx in zip(queryCharacters, queryIndices):
            arr[idx] = c
            best = 1
            run = 1
            for i in range(1, len(arr)):
                if arr[i] == arr[i - 1]:
                    run += 1
                    if run > best:
                        best = run
                else:
                    run = 1
            result.append(best)
        return result

