var longestRepeating = function(s, queryCharacters, queryIndices) {
    const arr = s.split('');
    const result = [];
    for (let q = 0; q < queryIndices.length; q++) {
        arr[queryIndices[q]] = queryCharacters[q];
        let best = 1;
        let run = 1;
        for (let i = 1; i < arr.length; i++) {
            if (arr[i] === arr[i - 1]) {
                run++;
                if (run > best) best = run;
            } else {
                run = 1;
            }
        }
        result.push(best);
    }
    return result;
};
